// Extrair dados da mensagem WhatsApp
const body = $input.first().json;

// Formato esperado do provedor WhatsApp
const phone = body.phone || body.from || body.contact?.phone || '';
const message = body.message || body.text || body.body || '';
const contactName = body.contact_name || body.contact?.name || body.profile?.name || 'Cliente';

// Normalizar telefone (remover + e espaços)
let normalizedPhone = phone.replace(/[^\d]/g, '');
if (normalizedPhone.startsWith('55') && normalizedPhone.length === 12) {
  // Já tem código país + DDD + número
} else if (normalizedPhone.length === 11) {
  // Adicionar código do Brasil
  normalizedPhone = '55' + normalizedPhone;
} else if (normalizedPhone.length === 10) {
  // Número sem 9º dígito
  normalizedPhone = '55' + normalizedPhone;
}

return {
  phone: normalizedPhone,
  message: message.trim().toLowerCase(),
  contactName: contactName.trim(),
  raw: body
};

// Formatar cardápio para WhatsApp
const menu = $input.first().json;

let response = `🍽️ *CARDÁPIO DO ${menu.restaurant.toUpperCase()}*\n\n`;

// Itens principais
response += `*PRINCIPAIS:*\n`;
menu.main_items.forEach((item, index) => {
  response += `${index + 1}. *${item.name}* - R$ ${item.formatted_price}\n`;
  if (item.description) {
    response += `   _${item.description}_\n`;
  }
});

// Itens extras
if (menu.extra_items.length > 0) {
  response += `\n*EXTRAS:*\n`;
  menu.extra_items.forEach((item, index) => {
    const itemNumber = menu.main_items.length + index + 1;
    response += `${itemNumber}. *${item.name}* - R$ ${item.formatted_price}\n`;
  });
}

response += `\n💡 *COMO PEDIR:*\n`;
response += `Digite o *NÚMERO* do prato desejado.\n`;
response += `Exemplo: \"1\" para ${menu.main_items[0]?.name || 'o primeiro prato'}\n\n`;
response += `📞 Precisou de ajuda? Digite \"atendente\"`;

return {
  message: response,
  menu: menu
};

const response = `⏰ *HORÁRIO DE FUNCIONAMENTO*

`;
response += `• *Segunda a Sábado:* 11h às 22h
`;
response += `• *Domingo:* 12h às 20h

`;
response += `🚚 *ENTREGA:*
`;
response += `• Taxa: R$ 5,00
`;
response += `• Tempo médio: 40 minutos

`;
response += `💳 *PAGAMENTO:*
`;
response += `• Dinheiro
• PIX
• Cartão (débito/crédito)
• VR/VA

`;
response += `Digite "cardapio" para ver nosso menu!`;

return { message: response };

const data = $input.first().json;
const name = data.contactName || 'Cliente';

const response = `👋 Olá *${name}*! Seja bem-vindo ao *Restaurante Dimas*!\n\n`;
response += `Eu sou o assistente virtual do Dimas. Como posso ajudar?\n\n`;
response += `*Opções rápidas:*\n`;
response += `• Digite \"cardapio\" para ver nosso menu\n`;
response += `• Digite \"horario\" para ver funcionamento\n`;
response += `• Digite \"entrega\" para informações de delivery\n\n`;
response += `Ou me diga o que você precisa! 😊`;

return { message: response };

// Este node seria expandido para processar pedidos completos
// Por enquanto, apenas uma mensagem informativa

const response = `🛒 *SISTEMA DE PEDIDOS*\n\n`;
response += `Para fazer um pedido, siga estes passos:\n\n`;
response += `1. Digite \"cardapio\" para ver o menu\n`;
response += `2. Digite o *NÚMERO* do prato desejado\n`;
response += `3. Informe a quantidade\n`;
response += `4. Escolha entrega ou retirada\n`;
response += `5. Confirme o pedido\n\n`;
response += `Vamos começar? Digite \"cardapio\"!`;

return { message: response };

const data = $input.first().json;

const response = `🤖 *ASSISTENTE DIMAS*\n\n`;
response += `Desculpe, não entendi \"${data.message}\".\n\n`;
response += `*Posso ajudar com:*\n`;
response += `• \"cardapio\" - Ver menu completo\n`;
response += `• \"horario\" - Horário de funcionamento\n`;
response += `• \"entrega\" - Informações de delivery\n`;
response += `• \"pedido\" - Fazer um pedido\n\n`;
response += `Ou digite \"atendente\" para falar com um humano.`;

return { message: response };
